			}
			shipID := total_ship + orderIdx
			ori := oris[orderIdx]
			des := dess[orderIdx]

			var bestAssignIdx int = -1
			var bestDelta float64 = 0.0
			var bestFeasible bool = false

			for ai := 0; ai < dispatch.AssignsLen; ai++ {
				assign := &dispatch.Assigns[ai]
				oldCost := assign.Cost
				ok := assign.AddShip(shipID, ori, des)
				if ok {
					assign.GenRoute()
					newCost := assign.Cost
					if newCost >= 0 {
						delta := newCost - oldCost
						if !bestFeasible || delta < bestDelta {
							bestDelta = delta
							bestAssignIdx = ai
							bestFeasible = true
						}
					}
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}

			if bestFeasible {
				dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[bestAssignIdx].GenRoute()
				inserted[orderIdx] = true
				continue
			}

			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				assign := &dispatch.Assigns[newIdx]
				ok := assign.AddShip(shipID, ori, des)
				if ok {
					assign.GenRoute()
					if assign.Cost >= 0 {
						dispatch.AssignsLen++
						inserted[orderIdx] = true
						continue
					} else {
						assign.RemoveShip(shipID)
						assign.GenRoute()
					}
				}
			}
		}
	}

	for oi := 0; oi < len(orders); oi++ {
		orderIdx := orders[oi].idx
		if inserted[orderIdx] {
			continue
		}
		shipID := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]

		fallbackDone := false
		for ai := 0; ai < dispatch.AssignsLen && !fallbackDone; ai++ {
			assign := &dispatch.Assigns[ai]
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					fallbackDone = true
					inserted[orderIdx] = true
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
		}
		if !fallbackDone && dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			assign := &dispatch.Assigns[newIdx]
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					dispatch.AssignsLen++
					inserted[orderIdx] = true
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}
